require("UI.UI_Challenge_Task")function UIMgr:UI_Challenge_Task_Create(a)local b;if GameMgr.Inst.prefer_language=='chs'or GameMgr.Inst.prefer_language=='chs_t'then b=LuaTools.LoadPrefab('prefab/ui_output/UI_Challenge_Task',a)else b=LuaTools.LoadPrefab('prefab/ui_output/UI_Challenge_Task',a)end;if not b then return nil end;b.gameObject:SetActive(false)local c=UI_Activity_Task:Create(b)c.txt_title=c.transform:Find("title"):GetComponent(typeof(UnityEngine.UI.Text))c.txt_title.text=Tools.StrOfLocalization(3188)c.txt_title.font=LuaTools.LoadFont(Tools.FontOfLocalization('fengyucumaokai'))c.btn_close=c.transform:Find("btn_close"):GetComponent(typeof(UnityEngine.UI.Button))c:OnCreate()local d=c:Inherit(UI_Challenge_Task)d:OnCreate()return d end